import { createSlice, configureStore } from "@reduxjs/toolkit";

const initialAddToCartState = { value: 0 };

const addToCartSlice = createSlice({
  name: "addToCart",
  initialState: initialAddToCartState,
  reducers: {
    addToCart(state) {
      state.value++;
    },
  },
});

const initialToggleCartState = false;

const toggleCart = createSlice({
  name: "toggleCart",
  initialState: initialToggleCartState,
  reducers: {},
});

const store = configureStore({
  reducer: { addToCart: addToCartSlice.reducer },
});

export const addToCartActions = addToCartSlice.actions;
export default store;
